function [nmbImg,imgLst,bgExst,bgName] = fStgImgListV01(espcDir,nmbSht)%% help for fStgImgListV01%% Function to get a list and number of images% for staging Dutch magspec analysis%% [nmbImg,imgLst] = fStgImgListV01(espcDir,nmbSht)%% Input% espcDir: a cell of directories to look for images% nmbSht: number of shots from logfile%% Output% nmbImg: number of images that all exist% imgLst: image list (list of shot number)% bgExst: 1 if bg exist for all% bgName: cell array for bgName% Written by Kei Nakamura% 2012/4/26, Thursday.% Ver.1 Created. Succeeded from fDutchShtLstallV01.m%% ver.2: %% main[imgExst1,bgExst1,bgName1] = fImgListV01(espcDir{1},nmbSht,'StagingMagnetCam3');    % get a list for cam1[imgExst2,bgExst2,bgName2] = fImgListV01(espcDir{2},nmbSht,'StagingMagnetCam2');    % get a list for cam2[imgExst3,bgExst3,bgName3] = fImgListV01(espcDir{3},nmbSht,'StagingMagnetCam1');    % get a list for cam3imgExst = imgExst1.*imgExst2.*imgExst3;   % 1 if all existnmbImg = sum(imgExst);                  % total number of shot all existaaa = [1:nmbSht]';imgExst = imgExst.*aaa;imgLst = find(imgExst~=0);bgExst = bgExst1*bgExst2*bgExst3;bgName{1} = bgName1; bgName{2} = bgName2; bgName{3} = bgName3;
